/* BTToggle styles — Figma 2855-1224 (light) · 4735-14291 (dark).
   All colors via @btech/tokens CSS vars — no hex fallbacks. */

.bt-toggle {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: var(--space-2xs);
  padding: var(--space-sm);
  border-radius: var(--radius-sm);
  border: 1px solid transparent;
  font-family: var(--typography-font-family-sans);
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  letter-spacing: 0;
  white-space: nowrap;
  cursor: pointer;
  user-select: none;
  outline: none;
  transition: background 0.15s, border-color 0.15s;
}

.bt-toggle:focus-visible {
  outline: 2px solid var(--color-brand-primary);
  outline-offset: 2px;
}

/* ── Small ── */
.bt-toggle--small {
  padding: var(--space-xs);
  font-size: var(--typography-font-size-xs);
}

/* ── Default variant — inactive ── */
.bt-toggle--default {
  background: var(--bg-subtle);
  color: var(--text-primary);
}
.bt-toggle--default:hover:not(:disabled) {
  background: var(--bg-subtler);
}

/* ── Default variant — active ── */
.bt-toggle--default.bt-toggle--active {
  background: var(--color-brand-primary);
  color: var(--text-inverse);
}
.bt-toggle--default.bt-toggle--active:hover:not(:disabled) {
  background: var(--color-brand-primary-bold);
}

/* ── Outline variant — inactive ── */
.bt-toggle--outline {
  background: transparent;
  color: var(--text-secondary);
  border-color: var(--border-primary);
}
.bt-toggle--outline:hover:not(:disabled) {
  background: var(--bg-subtle);
}

/* ── Outline variant — active ── */
.bt-toggle--outline.bt-toggle--active {
  background: var(--bg-subtle);
  color: var(--text-secondary);
  border-color: transparent;
}
.bt-toggle--outline.bt-toggle--active:hover:not(:disabled) {
  background: var(--bg-subtler);
}

/* ── Disabled ── */
.bt-toggle:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}

/* ── Icon wrappers ── */
.bt-toggle__icon {
  display: inline-flex;
  align-items: center;
  flex-shrink: 0;
}
.bt-toggle__icon img,
.bt-toggle__icon svg {
  width: 16px;
  height: 16px;
}

/* ── Dark mode (Figma 4735-14291) ─────────────────────────────────────────── */
/* bg.subtle === bg.primary in dark — use bg.secondary for neutral pill surfaces */
[data-mode="dark"] .bt-toggle--default:not(.bt-toggle--active) {
  background: var(--bg-secondary);
}
[data-mode="dark"] .bt-toggle--outline:hover:not(:disabled) {
  background: var(--bg-secondary);
}
[data-mode="dark"] .bt-toggle--outline.bt-toggle--active {
  background: var(--bg-secondary);
}

/**
 * BTToggle — pressable pill toggle atom.
 * Figma source: node 2855-1224.
 * Caller controls `pressed` state; component fires `onChange(!pressed)` on click.
 *
 * @example
 * ```tsx
 * // Default inactive
 * <BTToggle label="Option" onChange={onToggle} />
 *
 * // Controlled active
 * <BTToggle label="Bold" pressed={isBold} onChange={v => setIsBold(v)} />
 *
 * // Outline with icon
 * <BTToggle
 *   label="Bold"
 *   variant="outline"
 *   pressed={isBold}
 *   leftIcon={<BoldIcon />}
 *   onChange={v => setIsBold(v)}
 * />
 *
 * // Disabled
 * <BTToggle label="Option" disabled />
 * ```
 */
import './BTToggle.css';
import type { BTToggleProps } from './BTToggle.types';

export function BTToggle({
  label,
  pressed   = false,
  variant   = 'default',
  size      = 'default',
  disabled  = false,
  onChange,
  leftIcon,
  rightIcon,
  className,
}: BTToggleProps) {
  const cls = [
    'bt-toggle',
    `bt-toggle--${variant}`,
    pressed ? 'bt-toggle--active' : '',
    size === 'small' ? 'bt-toggle--small' : '',
    className ?? '',
  ]
    .filter(Boolean)
    .join(' ');

  function handleClick() {
    if (!disabled) onChange?.(!pressed);
  }

  return (
    <button
      className={cls}
      disabled={disabled}
      type="button"
      aria-pressed={pressed}
      data-testid="bt-toggle"
      onClick={handleClick}
    >
      {leftIcon  && <span className="bt-toggle__icon bt-toggle__icon--left">{leftIcon}</span>}
      <span className="bt-toggle__label">{label}</span>
      {rightIcon && <span className="bt-toggle__icon bt-toggle__icon--right">{rightIcon}</span>}
    </button>
  );
}

BTToggle.displayName = 'BTToggle';

export type BTToggleVariant = 'default' | 'outline';
export type BTToggleSize    = 'default' | 'small';

export interface BTToggleProps {
  /** Text shown inside the toggle. */
  label: string;
  /** Controlled pressed/active state. Default: false. */
  pressed?: boolean;
  /** Visual style. Default: 'default'. */
  variant?: BTToggleVariant;
  /** Padding scale. Default: 'default'. */
  size?: BTToggleSize;
  /** Disables interaction and applies opacity:0.5. Default: false. */
  disabled?: boolean;
  /** Fired when user clicks — receives the new pressed value. */
  onChange?: (pressed: boolean) => void;
  /** Icon rendered before the label (React only). */
  leftIcon?: React.ReactNode;
  /** Icon rendered after the label (React only). */
  rightIcon?: React.ReactNode;
  /** Extra class name (React only). */
  className?: string;
}
